```typescript
{approvals.map((a) => (
  <button onClick={() => handleApproval(a.id, 'REJECTED', a.nama)}>Tolak</button>
  <button onClick={() => handleApproval(a.id, 'APPROVED', a.nama)}>Setujui</button>
